<section class="admin-page-head"><div><p class="eyebrow">OPERAȚIUNI</p><h1>Comenzi</h1></div><a class="admin-button secondary" href="?export=csv">Export CSV</a></section><section class="admin-panel"><form class="admin-filters" method="get"><input type="search" name="q" value="<?= e($q) ?>" placeholder="Număr, client, email sau telefon"><select name="status"><option value="">Toate statusurile</option><?php foreach(['new','confirmed','processing','ready_for_shipping','shipped','delivered','cancelled','returned','refunded'] as $item): ?><option <?= $status===$item?'selected':'' ?>><?= e($item) ?></option><?php endforeach; ?></select><button class="admin-button" type="submit">Filtrează</button></form><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Comandă</th><th>Client</th><th>Plată</th><th>Status</th><th>Data</th><th>Total</th></tr></thead><tbody><?php foreach($orders as $order): ?><tr><td><a href="<?= e(url('/admin/comenzi/'.$order['id'])) ?>"><strong><?= e($order['order_number']) ?></strong></a></td><td><?= e($order['email']) ?><small><?= e($order['phone']) ?></small></td><td><span class="status-pill"><?= e($order['payment_status']) ?></span></td><td><span class="status-pill accent"><?= e($order['order_status']) ?></span></td><td><?= date('d.m.Y H:i',strtotime($order['created_at'])) ?></td><td><?= money($order['grand_total_minor']) ?></td></tr><?php endforeach; ?></tbody></table></div></section>

